var buy={services:[],limit:0,packId:0,giftId:0,init:function(){$(".btn-pack-buy").click(function(){buy.showPackDialog($(this).data("packId"))});$(".btn-gift-activate").click(function(){buy.showGiftDialog($(this).data("giftId"))});$("#i_pack_dialog_save").click(function(){var a=$("#i_balance_add_value").val();if(a>0){location.href="/orders/action?"+$("#i_form_pack_select").serialize();return}$(".c-service").each(function(){var b=$(this).val();if(b==""){$(this).addClass("alert-danger")}});$(".c-groupId").each(function(){var b=$(this).val();if(b==0){$("#"+$(this).attr("id")+"_title").addClass("alert-danger")}});location.href="/orders/action?"+$("#i_form_pack_select").serialize()});$(".c-balance-another").click(function(){buy.showPackDialog(0)});$("#i_pack_dialog").on("shown.bs.modal",function(){buy.getGroupsList()})},getGroupsList:function(){$.ajax({type:"post",dataType:"json",data:{action:"getPackForm",packId:buy.packId,giftId:buy.giftId},beforeSend:function(){$("#i_pack_dialog_title").html("Подождите...");$("#i_pack_dialog_progress").show()},success:function(a){if(a.success){if(a.redirect){location.href=a.href}buy.limit=a.limit;$("#i_pack_dialog_title").html(a.title);$("#i_pack_dialog_container").html(a.html)}else{$("#i_pack_dialog_container").html('<div class="alert alert-danger">'+a.errorText+"</div>")}},complete:function(){$("#i_pack_dialog_progress").hide()},error:function(){$("#i_pack_dialog_container").html('<div class="alert alert-danger">Не удалось выполнить запрос. Попробуйте позднее</div>')}})},serviceSelect:function(b){var a=$(b).data("service");var c=false;for(i in buy.services){if(buy.services[i]==a){buy.services.splice(i,1);$(b).removeClass("btn-success");c=true;break}}if(!c&&buy.services.length<buy.limit){buy.services.push(a);$(b).addClass("btn-success")}},showGiftDialog:function(a){buy.giftId=a;$("#i_pack_dialog").modal()},showPackDialog:function(a){buy.packId=a;$("#i_pack_dialog").modal()}};$(document).ready(function(){buy.init()});